// Merge global + AU/NZ NewsAPI responses into a single deduplicated article list
const allItems = $input.all();
const combined = [];
const seen = new Set();

for (const item of allItems) {
  const articles = item.json.articles || [];
  for (const a of articles) {
    if (!seen.has(a.url)) {
      seen.add(a.url);
      combined.push(a);
    }
  }
}

console.log(`Merged ${combined.length} unique articles (global + AU/NZ sources).`);
return [{ json: { articles: combined, status: 'ok', totalResults: combined.length } }];

// Pull existing company names to deduplicate
const sheet = $('Get Existing Companies').first().json;
const rows = sheet.values || [];
const existing = new Set(rows.slice(1).map(r => (r[0]||'').toLowerCase().trim()));

// Pull merged articles (global + AU/NZ)
const news = $('Merge Article Lists').first().json;
const articles = news.articles || [];

// Keyword filters — must mention layoffs AND AI
const layoffWords = ['layoff','redundan','job cut','workforce reduction','headcount','dismiss','let go','downsiz'];
const aiWords     = ['artificial intelligence',' ai ','automation','machine learning','generative ai','llm','chatgpt','claude','copilot'];

const candidates = articles.filter(a => {
  const text = ((a.title||'') + ' ' + (a.description||'')).toLowerCase();
  return layoffWords.some(k => text.includes(k)) && aiWords.some(k => text.includes(k));
});

if (!candidates.length) {
  console.log('No new layoff+AI articles found in this cycle.');
  return [];
}

console.log(`Found ${candidates.length} candidate articles.`);

return candidates.map(a => ({ json: {
  title:       a.title       || '',
  description: a.description || '',
  source:      a.source?.name || '',
  url:         a.url         || '',
  publishedAt: a.publishedAt || '',
  existing:    JSON.stringify([...existing])   // pass along for dedup in next node
}}));

// Sanitize title & description before JSON interpolation.
// Removes control chars, replaces double-quotes with single-quotes,
// and normalises backslashes — prevents 'JSON parameter needs to be
// valid JSON' errors in the Claude Haiku HTTP Request node.
const sanitize = (str, maxLen) =>
  (str || '')
    .replace(/[\x00-\x1f\x7f]/g, ' ')  // strip control chars (newlines etc)
    .replace(/"/g, "'")                 // " → ' (safe inside JSON string)
    .replace(/\\/g, '/')                // backslash → forward-slash
    .trim()
    .substring(0, maxLen);

return [{ json: {
  ...$json,
  titleSafe: sanitize($json.title, 300),
  descSafe:  sanitize($json.description, 500)
}}];

