// Parse Claude's JSON response
const raw = $json.content?.[0]?.text || '{}';

let parsed;
try {
  parsed = JSON.parse(raw.replace(/```json|```/gi,'').trim());
} catch(e) {
  console.log('Parse failed for:', raw);
  return [];
}

// Validate
if (!parsed.company || typeof parsed.headcount === 'undefined') return [];

// Normalise
parsed.headcount    = parseInt(parsed.headcount) || 0;
parsed.aiConfidence = ['genuine','washing','restructure'].includes(parsed.aiConfidence)
  ? parsed.aiConfidence : 'restructure';
parsed.date = (parsed.date||'').substring(0,7);
parsed.quote = (parsed.quote||'').substring(0,200);

// Date sanity check — if Claude's date is >6 months before article publish date, use publishedAt instead
const publishedAt = ($json.publishedAt || '').substring(0,7);
if (publishedAt) {
  const claudeMs = new Date(parsed.date + '-01').getTime();
  const pubMs    = new Date(publishedAt + '-01').getTime();
  if (pubMs - claudeMs > 6 * 30 * 24 * 60 * 60 * 1000) {
    console.log(`Date override: Claude said ${parsed.date}, article published ${publishedAt}`);
    parsed.date = publishedAt;
  }
}

// ── Rolling 1-year gate ──────────────────────────────────────
// Reject any entry whose date falls outside today - 12 months.
// This is the single source of truth for the date window —
// matches the oneYearAgo filter in the React dashboard exactly.
const oneYearAgo = new Date();
oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
const entryDate = new Date((parsed.date || '1970-01') + '-01');
if (entryDate < oneYearAgo) {
  console.log(`Skipping out-of-window: ${parsed.company} (${parsed.date}) — older than rolling 1-year cutoff (${oneYearAgo.toISOString().substring(0,7)})`);
  return [];
}
// ────────────────────────────────────────────────────────────

// Skip zero headcount or bad dates
if (parsed.headcount === 0 || !/^\d{4}-\d{2}$/.test(parsed.date)) return [];

// Dedup check against existing sheet companies
const existing = JSON.parse($json.existing || '[]');
if (existing.includes(parsed.company.toLowerCase().trim())) {
  console.log(`Skipping duplicate: ${parsed.company}`);
  return [];
}

return [{ json: parsed }];

// Deduplicate within this run — prevents double-writes when both global
// and AU/NZ feeds return articles about the same company.
const items = $input.all();
const seen = new Set();
const unique = [];
for (const item of items) {
  const key = (item.json.company || '').toLowerCase().trim();
  if (key && !seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}
console.log(`Dedup: ${items.length} → ${unique.length} unique companies.`);
return unique;

// Summary log at end of run
const items = $input.all();
console.log(`Run complete. ${items.length} new records written to Google Sheet.`);
return items;
